/** Icons that have a font glyph — usable via PDS-Icon-Font-20 **/
export const fontIcons: IconEntry[] = icons.filter(i => i.inFont);

/** Icons available as SVG only **/
export const svgIcons: IconEntry[] = icons.filter(i => !i.inFont);

/** Look up an icon entry by name **/
export function getIcon(name: IconName): IconEntry | undefined {
  return icons.find(i => i.name === name);
}

/** Get the Unicode character for a font icon (use as content in CSS or JSX) **/
export function getIconChar(name: IconName): string | undefined {
  return icons.find(i => i.name === name)?.unicode;
}

/** Map of icon name → unicode character (font icons only) **/
export const iconCharMap: Partial<Record<IconName, string>> = Object.fromEntries(
  icons.filter(i => i.inFont && i.unicode).map(i => [i.name, i.unicode!])
);
